import{_ as a,o as t,c as i,a3 as n}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"AI Features Overview","description":"Understand AI capabilities, writing support, and search enhancers in Notely.","frontmatter":{"title":"AI Features Overview","description":"Understand AI capabilities, writing support, and search enhancers in Notely.","keywords":"ai, writing assistant, LLM, local llm, OpenAI, HuggingFace","category":"AI"},"headers":[],"relativePath":"ai/index.md","filePath":"ai/index.md","lastUpdated":1784354374000}'),r={name:"ai/index.md"};function o(l,e,s,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="ai-overview" tabindex="-1">AI Overview <a class="header-anchor" href="#ai-overview" aria-label="Permalink to &quot;AI Overview&quot;">​</a></h1><p>Notely includes an integrated AI layer that enhances writing speed, assists in searching, and uncovers visual relationships between notes.</p><h2 id="what-ai-can-do" tabindex="-1">What AI Can Do <a class="header-anchor" href="#what-ai-can-do" aria-label="Permalink to &quot;What AI Can Do&quot;">​</a></h2><ul><li><strong>AI Chat Panel</strong>: Ask questions about your workspace notes or brainstorm topics.</li><li><strong>AI Palette Actions</strong>: Refactor, rewrite, summarize, or change the tone of selected text in the editor.</li><li><strong>Semantic Search</strong>: Search by intent and meaning rather than exact word matching.</li><li><strong>Semantic Clustering</strong>: Automates grouping of visually related files in the Workspace Graph.</li></ul><hr><h2 id="technical-security-offline-compatibility" tabindex="-1">Technical Security &amp; Offline Compatibility <a class="header-anchor" href="#technical-security-offline-compatibility" aria-label="Permalink to &quot;Technical Security &amp; Offline Compatibility&quot;">​</a></h2><p>Notely supports local models to keep your note data fully private:</p><ul><li>Configure a local API endpoint (e.g., via Ollama, LM Studio) to run AI entirely offline.</li><li>Alternatively, connect to cloud services like OpenAI or HuggingFace.</li><li>Requests are only triggered when you actively launch an AI action.</li></ul>',8)])])}const g=a(r,[["render",o]]);export{p as __pageData,g as default};
